import { getBaseMark4BarMarker } from '../bar/bar-marker-helpers';
import { ParserRegistry } from '../core/parser-registry';

export function _whiskerMark(data, phase, condition) {
    const KEY = 'whiskers',
        KEY_MERGED = 'whiskersOptionsMerged';

    let _this = this,
        isWhiskerOnEdges = _this.builderC[KEY].showOn == 'edges',
        highlightPhase = phase === 'highlight',
        options = highlightPhase ? this.builderC[KEY_MERGED].hoveroptions : this.builderC[KEY_MERGED];

    let _whiskerG = {
        mark: 'g',
        selector: `.whiskerSeries${this.builderC.datasetIndex}`,
        data: data.disabled || !condition ? [] : [data.data],
        children: []
    };
    if(condition){
        let args_data = highlightPhase ? data.data : null;
        if (isWhiskerOnEdges) {
            let whiskerMark_0 = getBaseMark4BarMarker.call(this, KEY, args_data, options, 0),
                whiskerMark_1 = getBaseMark4BarMarker.call(this, KEY, args_data, options, 1);
            _whiskerG.children.push(whiskerMark_0, whiskerMark_1);
        } else {
            let whiskerMark = getBaseMark4BarMarker.call(this, KEY, args_data, options);
            _whiskerG.children.push(whiskerMark);
        }
    }
    return _whiskerG;
}

ParserRegistry.marks('boxplot.whisker', _whiskerMark);
